import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  AppBar,
  Toolbar,
  Typography,
  Button,
  IconButton,
  Menu,
  MenuItem,
  Box,
  Avatar,
  useTheme,
  CircularProgress,
  Alert,
} from '@mui/material';
import {
  HomeIcon,
  BriefcaseIcon,
  UsersIcon,
  ChartBarIcon,
  UserCircleIcon,
  ArrowRightOnRectangleIcon,
  KeyIcon,
} from '@heroicons/react/24/outline';
import { motion } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';

const Navbar: React.FC = () => {
  const theme = useTheme();
  const navigate = useNavigate();
  const { user, logout, loading, error } = useAuth();
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);

  const handleMenu = (event: React.MouseEvent<HTMLElement>) => setAnchorEl(event.currentTarget);
  const handleClose = () => setAnchorEl(null);
  const handleLogout = async () => {
    try {
      await logout();
      handleClose();
      navigate('/login');
    } catch (err) {
      console.error('Logout failed:', err);
    }
  };

  const buttonVariants = {
    hover: { scale: 1.05, boxShadow: '0px 4px 20px rgba(0, 0, 0, 0.2)' },
    tap: { scale: 0.95 },
  };

  if (loading) {
    return (
      <AppBar
        position="static"
        elevation={0}
        sx={{
          background: 'linear-gradient(135deg, #1e3a8a 0%, #3b82f6 100%)',
          backdropFilter: 'blur(10px)',
          WebkitBackdropFilter: 'blur(10px)',
        }}
      >
        <Toolbar sx={{ justifyContent: 'center' }}>
          <CircularProgress size={24} color="inherit" />
        </Toolbar>
      </AppBar>
    );
  }

  const getHomePath = () => {
    if (!user) return '/';
    switch (user.role) {
      case 'APPLICANT':
        return '/applicant/home';
      case 'RECRUITER':
        return '/recruiter/home';
      case 'ADMIN':
        return '/admin/home';
      default:
        return '/';
    }
  };

  return (
    <AppBar
      position="static"
      elevation={0}
      sx={{
        background: 'linear-gradient(135deg, rgba(30,58,138,0.9) 0%, rgba(59,130,246,0.9) 100%)',
        backdropFilter: 'blur(10px)',
        WebkitBackdropFilter: 'blur(10px)',
        borderBottom: `1px solid rgba(255,255,255,0.1)`,
      }}
    >
      {error && (
        <Alert severity="error" sx={{ borderRadius: 0 }}>
          {error}
        </Alert>
      )}
      <Toolbar sx={{ py: 1.5 }}>
        <Box component={motion.div} whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }} sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <HomeIcon className="h-6 w-6" style={{ color: theme.palette.common.white }} />
          <Typography
            variant="h6"
            component={Link}
            to={getHomePath()}
            sx={{
              textDecoration: 'none',
              color: 'common.white',
              fontWeight: 700,
              '&:hover': { color: 'common.white', opacity: 0.8 },
            }}
          >
            HunterBot
          </Typography>
        </Box>

        {user && (
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, ml: 4 }}>
            {['RECRUITER', 'ADMIN'].includes(user.role) && (
              <motion.div variants={buttonVariants} whileHover="hover" whileTap="tap">
                <Button
                  component={Link}
                  to="/recruiter/create-job"
                  variant="text"
                  sx={{
                    color: 'common.white',
                    textTransform: 'none',
                    '&:hover': { color: 'common.white', opacity: 0.8 },
                  }}
                  startIcon={<BriefcaseIcon className="h-5 w-5" />}
                >
                  + Create New Job
                </Button>
              </motion.div>
            )}
            <motion.div variants={buttonVariants} whileHover="hover" whileTap="tap">
              <Button
                component={Link}
                to={user.role === 'APPLICANT' ? '/applicant/jobs' : '/recruiter/jobs'}
                variant="text"
                sx={{
                  color: 'common.white',
                  textTransform: 'none',
                  '&:hover': { color: 'common.white', opacity: 0.8 },
                }}
                startIcon={<BriefcaseIcon className="h-5 w-5" />}
              >
                Jobs
              </Button>
            </motion.div>
            {['RECRUITER', 'ADMIN'].includes(user.role) && (
              <motion.div variants={buttonVariants} whileHover="hover" whileTap="tap">
                <Button
                  component={Link}
                  to="/recruiter/candidates"
                  variant="text"
                  sx={{
                    color: 'common.white',
                    textTransform: 'none',
                    '&:hover': { color: 'common.white', opacity: 0.8 },
                  }}
                  startIcon={<UsersIcon className="h-5 w-5" />}
                >
                  Candidate
                </Button>
              </motion.div>
            )}
            {user.role === 'ADMIN' && (
              <motion.div variants={buttonVariants} whileHover="hover" whileTap="tap">
                <Button
                  component={Link}
                  to="/admin/reports"
                  variant="text"
                  sx={{
                    color: 'common.white',
                    textTransform: 'none',
                    '&:hover': { color: 'common.white', opacity: 0.8 },
                  }}
                  startIcon={<ChartBarIcon className="h-5 w-5" />}
                >
                  Report
                </Button>
              </motion.div>
            )}
          </Box>
        )}

        <Box sx={{ flexGrow: 1 }} />

        {user ? (
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
            <IconButton
              component={motion.button}
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
              onClick={handleMenu}
            >
              <Avatar sx={{ width: 36, height: 36, bgcolor: 'primary.main', color: 'common.white' }}>
                {user.name?.[0]?.toUpperCase() || 'U'}
              </Avatar>
            </IconButton>
            <Menu
              anchorEl={anchorEl}
              open={Boolean(anchorEl)}
              onClose={handleClose}
              PaperProps={{
                elevation: 0,
                sx: {
                  mt: 1.5,
                  borderRadius: 2,
                  minWidth: 200,
                  bgcolor: 'rgba(255,255,255,0.95)',
                  background: 'linear-gradient(145deg, rgba(255,255,255,0.95) 0%, rgba(240,240,245,0.9) 100%)',
                  boxShadow: '0 8px 32px rgba(0, 0, 0, 0.2)',
                  '&:before': {
                    content: '""',
                    display: 'block',
                    position: 'absolute',
                    top: 0,
                    right: 14,
                    width: 10,
                    height: 10,
                    bgcolor: 'rgba(255,255,255,0.95)',
                    transform: 'translateY(-50%) rotate(45deg)',
                    zIndex: 0,
                  },
                },
              }}
              transformOrigin={{ horizontal: 'right', vertical: 'top' }}
              anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
            >
              {user.role === 'APPLICANT' && (
                <MenuItem
                  component={Link}
                  to="/applicant/profile"
                  onClick={handleClose}
                  sx={{ display: 'flex', gap: 1, py: 1.5, color: 'text.primary' }}
                >
                  <UserCircleIcon className="h-5 w-5" />
                  Profile
                </MenuItem>
              )}
              <MenuItem
                onClick={handleLogout}
                sx={{ display: 'flex', gap: 1, py: 1.5, color: 'text.primary' }}
              >
                <ArrowRightOnRectangleIcon className="h-5 w-5" />
                Logout
              </MenuItem>
            </Menu>
          </Box>
        ) : (
          <Box sx={{ display: 'flex', gap: 2 }}>
            <Button
              component={motion.button}
              variants={buttonVariants}
              whileHover="hover"
              whileTap="tap"
              variant="text"
              onClick={() => navigate('/forgot-password')}
              sx={{
                color: 'common.white',
                textTransform: 'none',
                '&:hover': { color: 'common.white', opacity: 0.8 },
              }}
              startIcon={<KeyIcon className="h-5 w-5" />}
            >
              Forgot Password
            </Button>
            <Button
              component={motion.button}
              variants={buttonVariants}
              whileHover="hover"
              whileTap="tap"
              variant="outlined"
              onClick={() => navigate('/login')}
              sx={{
                borderRadius: 8,
                px: 3,
                py: 1,
                color: 'common.white',
                borderColor: 'rgba(255,255,255,0.5)',
                '&:hover': { borderColor: 'common.white', bgcolor: 'rgba(255,255,255,0.1)' },
              }}
            >
              Login
            </Button>
            <Button
              component={motion.button}
              variants={buttonVariants}
              whileHover="hover"
              whileTap="tap"
              variant="contained"
              onClick={() => navigate('/register')}
              sx={{
                borderRadius: 8,
                px: 3,
                py: 1,
                bgcolor: 'primary.main',
                '&:hover': { bgcolor: 'primary.dark', boxShadow: '0 4px 15px rgba(0, 0, 0, 0.3)' },
              }}
            >
              Register
            </Button>
          </Box>
        )}
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
